/**
 * @summary Get recent query history
 */
export const getGetQueryHistoryUrl = (params?: GetQueryHistoryParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/query/history?${stringifiedParams}`
    : `/api/query/history`;
};

export const getQueryHistory = async (
  params?: GetQueryHistoryParams,
  options?: RequestInit,
): Promise<QueryHistoryResponse> => {
  return customFetch<QueryHistoryResponse>(getGetQueryHistoryUrl(params), {
    ...options,
    method: "GET",
  });
};

